// Parse Claude's JSON response into rows for the Voice Profile tab
const raw = $input.first().json;
let profile;
try {
  let text = raw.claude_response.trim();
  if (text.startsWith('```json')) text = text.replace(/^```json\s*/, '').replace(/\s*```$/, '');
  else if (text.startsWith('```')) text = text.replace(/^```\s*/, '').replace(/\s*```$/, '');
  profile = JSON.parse(text);
} catch (e) {
  const match = raw.claude_response.match(/\{[\s\S]*\}/);
  if (match) {
    profile = JSON.parse(match[0]);
  } else {
    throw new Error('Could not parse Voice Profile JSON from Claude response');
  }
}

const categoryMap = {
  tone: 'Core', formality: 'Core', energy: 'Core', humor: 'Core', perspective: 'Core',
  sentence_style: 'Writing Rules', paragraph_length: 'Writing Rules', vocabulary: 'Writing Rules',
  person: 'Writing Rules', reference_blend: 'Writing Rules',
  opening_style: 'Content Patterns', cta_style: 'Content Patterns', closing_style: 'Content Patterns',
  always_use: 'Guardrails', never_use: 'Guardrails', sensitive_topics: 'Guardrails',
  sample_opening_1: 'Calibration', sample_opening_2: 'Calibration', sample_opening_3: 'Calibration'
};

// Build rows for Google Sheets
const rows = [];
for (const [key, value] of Object.entries(profile)) {
  if (key === 'calibration_notes') continue; // handled separately
  rows.push({
    Attribute: key,
    Value: typeof value === 'string' ? value : JSON.stringify(value),
    Category: categoryMap[key] || 'Metadata'
  });
}

// Add metadata rows
rows.push({ Attribute: 'source', Value: raw.source, Category: 'Metadata' });
rows.push({ Attribute: 'generated_date', Value: new Date().toISOString().split('T')[0], Category: 'Metadata' });
rows.push({ Attribute: 'calibration_status', Value: 'Calibrating', Category: 'Metadata' });
rows.push({ Attribute: 'calibration_score', Value: '', Category: 'Metadata' });

return [{
  json: {
    rows: rows,
    client_name: raw.client_name,
    sheet_id: raw.sheet_id,
    source: raw.source,
    calibration_notes: profile.calibration_notes || '',
    profile_summary: 'Tone: ' + (profile.tone || '') + ' | Formality: ' + (profile.formality || '') + ' | Energy: ' + (profile.energy || '')
  }
}];

// Split the rows array into individual items for Google Sheets append
const data = $input.first().json;
return data.rows.map(row => ({ json: row }));
